text:
{
  "formal_minutes": {
    "decisions": [
      "팀은 공개 릴리스를 당장 수요일로 밀지 않고, 스모크 테스트 통과를 조건으로 금요일 15:00 KST를 공개 배포 목표로 확정했다.",
      "packageName mismatch 발생 시 `smoke-theme-pack.mjs`를 변경해 무시 처리하지 않기로 했다. 먼저 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 리뷰를 진행한다."
    ],
    "rejected_proposals": [
      "Hara가 제안한 `smoke-theme-pack.mjs`에서 packageName 불일치 무시 처리안은 반려됨."
    ],
    "non_decisions": [
      "README 설치 단계 리뷰는 목요일에 가능한 경우 진행하자는 제안은 있었으나, 책임자와 확정 기한은 정해지지 않음.",
      "Hara가 수행할 tarball 경로 확인은 Minjun의 스모크 결과 공유 후 진행하기로 했으나 완료 기한은 미정.",
      "최종 공개 릴리스 승인 권한자의 지정은 미정."
    ],
    "internal_stretch_goals": [
      "수요일 릴리스는 내부 스트레치 골로만 유지."
    ],
    "risks": [
      "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음.",
      "README 설치 절차가 오래된 상태면 공개 릴리스 노트/안내가 사용자에게 오해를 줄 수 있음."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 기재할지 여부."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 원인 정리 노트를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성 tarball 경로 확인",
      "due": "미정 (결과 공유 후)",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차 검토(목요일 가능 시)",
      "due": "미정",
      "status": "미결/조건부",
      "source_certainty": "low"
    }
  ],
  "followup_note": {
    "next_check": [
      "금요일 10:00 KST까지 Minjun의 스모크 테스트 결과 수신 여부 확인.",
      "스모크 통과 시 금요일 15:00 KST 공개 릴리스 진행 가능 여부 확정.",
      "Hara의 tarball 경로 확인 결과 반영 및 경로 오류 리스크 완화.",
      "README 검토 담당자 지정 여부와 리뷰 완료 상태 확정.",
      "최종 승인 권한자 지정 및 릴리스 노트 문구(수요일 스트레치 반영 포함 여부) 확정."
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너명",
      "예산, 보안 사고, 장애, 법무 승인 요건",
      "문서에 없는 owner, 최종 승인자, 확정된 데드라인"
    ]
  },
  "non_invention_rules": [
    "회의록에 명시되지 않은 고객/예산/보안/장애/법무/딜레이트(완료기한) 등 사실을 추가하지 않는다.",
    "주어진 fixture에 없는 인물, 책임자, 조직적 권한, 일정은 추측 없이 '미정' 또는 '미확정'으로만 표기한다.",
    "제안/의견과 확정사항을 구분하고, 확인되지 않은 내용은 결정 또는 사실로 작성하지 않는다."
  ]
}
